import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

changes = []
unchanged = []
for bp in baseline['projects']:
    name = bp['path'].split('/')[-1]
    ap = next((p for p in after['projects'] if p['path'] == bp['path']), None)
    if not ap: print(f'MISSING: {name}'); continue
    for bf in bp['frameworks']:
        fw = bf['framework']
        af = next((f for f in ap['frameworks'] if f['framework'] == fw), None)
        if not af: print(f'MISSING FW: {name}/{fw}'); continue
        bpkgs = {p['id']: p['resolvedVersion'] for p in bf['topLevelPackages']}
        apkgs = {p['id']: p['resolvedVersion'] for p in af['topLevelPackages']}
        for pkg in sorted(set(list(bpkgs.keys()) + list(apkgs.keys()))):
            bv = bpkgs.get(pkg, 'N/A')
            av = apkgs.get(pkg, 'N/A')
            if bv != av:
                changes.append((name, fw, pkg, bv, av))
            else:
                unchanged.append((name, fw, pkg, bv))

print('=== CHANGES ===')
for c in changes:
    print(f'{c[0]} ({c[1]}): {c[2]} {c[3]} -> {c[4]}')
if not changes:
    print('None')
print(f'\n=== UNCHANGED: {len(unchanged)} packages ===')
for u in unchanged:
    print(f'{u[0]} ({u[1]}): {u[2]} = {u[3]}')
"

